from flask import Flask, jsonify, request
from flask_cors import CORS
from aadhaar import extract_aadhaar
import os

app = Flask(__name__)
CORS(app, resources={r"/*": {"origins": "*", "allow_headers": "*", "methods": ["GET", "POST", "OPTIONS"]}})

HARDCODED_PDF_BASE64 = ""


@app.route("/")
def health_check():
    return jsonify({"status": "ok", "message": "Aadhaar Extraction API is running."})


@app.route("/extract", methods=["GET", "POST"], strict_slashes=False)
def extract():
    """
    Extracts Aadhaar details from the hardcoded PDF and returns structured data.
    Ignores request body, query params, and Content-Type entirely.
    """
    request.get_data()  # consume body without parsing, regardless of Content-Type
    try:
        result = extract_aadhaar(HARDCODED_PDF_BASE64)
        return jsonify({
            "aadhaar_no": result["Aadhaar No"],
            "name": result["Name"],
            "date_of_birth": result["Date of Birth"],
            "gender": result["Gender"],
            "address": result["Address"]
        })
    except Exception as e:
        return jsonify({"error": str(e)}), 500


if __name__ == "__main__":
    port = int(os.environ.get("PORT", 8000))
    app.run(host="0.0.0.0", port=port)
